function icon(name, cls = '') {
  return `<span class="icon ${cls}" aria-hidden="true">${ICONS[name] || ICONS.code}</span>`;
}

// ── DATE UTILITIES ─────────────────────────────────────────
function parseYearMonth(str) {
  if (!str) return null;
  const parts = str.split('-');
  return new Date(parseInt(parts[0]), parseInt(parts[1] || 1) - 1, 1);
}

function getDynamicYears(startDateStr) {
  const start = parseYearMonth(startDateStr);
  if (!start) return '3';
  const now = new Date();
  const years = (now - start) / (1000 * 60 * 60 * 24 * 365.25);
  return Math.floor(years).toString();
}

function formatPeriod(period) {
  if (!period) return '';
  if (typeof period === 'string') return period;
  const start = parseYearMonth(period.start);
  const end   = period.end ? parseYearMonth(period.end) : null;
  const fmtOpts = { month: 'short', year: 'numeric' };
  const startStr = start ? start.toLocaleDateString('en-US', fmtOpts) : '';
  const endStr   = end   ? end.toLocaleDateString('en-US', fmtOpts) : 'Present';
  return `${startStr} – ${endStr}`;
}

function getDurationMonths(period) {
  if (!period || typeof period === 'string') return '';
  const start = parseYearMonth(period.start);
  const end   = period.end ? parseYearMonth(period.end) : new Date();
  if (!start) return '';
  const months = Math.round((end - start) / (1000 * 60 * 60 * 24 * 30.44));
  const years  = Math.floor(months / 12);
  const rem    = months % 12;
  if (years > 0 && rem > 0) return `${years}y ${rem}m`;
  if (years > 0) return `${years}y`;
  return `${months}m`;
}

// ── HELPERS ────────────────────────────────────────────────
function esc(str) {
  const el = document.createElement('div');
  el.textContent = str;
  return el.innerHTML;
}

function resolveStatValue(stat, content) {
  if (stat.value === 'dynamic:experience') {
    return getDynamicYears(content.personal.experienceStartDate);
  }
  return stat.value;
}

// ── RENDER: NAV ────────────────────────────────────────────
function renderNav(content) {
  const { nav, personal } = content;
  const links = nav.links.map(l =>
    `<a class="nav__link" href="${l.href}" data-href="${l.href}">${esc(l.label)}</a>`
  ).join('');

  document.getElementById('nav').innerHTML = `
    <div class="nav__inner">
      <a class="nav__logo" href="#hero">${esc(nav.logo)}</a>
      <nav class="nav__links" aria-label="Main navigation">
        ${links}
        <a class="nav__link nav__cta" href="${personal.resumeDownload}" target="_blank" rel="noopener">
          ${icon('download', 'btn-icon')} Resume
        </a>
      </nav>
      <button class="nav__hamburger" id="hamburger" aria-label="Toggle menu" aria-expanded="false">
        <span></span><span></span><span></span>
      </button>
    </div>
    <nav class="nav__mobile" id="mobileMenu" aria-label="Mobile navigation">
      ${nav.links.map(l => `<a class="nav__link" href="${l.href}">${esc(l.label)}</a>`).join('')}
      <a class="nav__link" href="${personal.resumeDownload}" target="_blank" rel="noopener">
        ${icon('download', 'btn-icon')} Resume
      </a>
    </nav>
  `;
}

