// ── TYPING ANIMATION ───────────────────────────────────────
function initTypingAnimation(words) {
  const el = document.getElementById('typingText');
  if (!el || !words || !words.length) return;

  let wordIndex  = 0;
  let charIndex  = 0;
  let isDeleting = false;
  let isPaused   = false;

  function type() {
    const current = words[wordIndex];

    if (isPaused) {
      isPaused = false;
      setTimeout(type, 1800);
      return;
    }

    if (!isDeleting) {
      el.textContent = current.substring(0, charIndex + 1);
      charIndex++;
      if (charIndex === current.length) {
        isDeleting = true;
        isPaused   = true;
        setTimeout(type, 60);
        return;
      }
      setTimeout(type, 80);
    } else {
      el.textContent = current.substring(0, charIndex - 1);
      charIndex--;
      if (charIndex === 0) {
        isDeleting = false;
        wordIndex  = (wordIndex + 1) % words.length;
      }
      setTimeout(type, 45);
    }
  }

  type();
}

// ── COUNTER ANIMATION ──────────────────────────────────────
function animateCounters() {
  document.querySelectorAll('[data-target]').forEach(el => {
    const target = parseInt(el.dataset.target, 10);
    const suffix = el.dataset.suffix || '';
    if (isNaN(target)) { el.textContent = el.dataset.target + suffix; return; }

    let start = 0;
    const duration = 1800;
    const step = target / (duration / 16);

    function update() {
      start = Math.min(start + step, target);
      el.textContent = Math.floor(start) + suffix;
      if (start < target) requestAnimationFrame(update);
    }
    update();
  });
}

// ── SCROLL REVEAL ──────────────────────────────────────────
function initScrollReveal() {
  const revealEls = document.querySelectorAll('.reveal, .reveal-left, .reveal-right');
  if (!revealEls.length) return;

  const observer = new IntersectionObserver((entries) => {
    entries.forEach(entry => {
      if (entry.isIntersecting) {
        entry.target.classList.add('visible');
        // Trigger counters when hero stats come into view
        if (entry.target.querySelector('[data-target]')) {
          animateCounters();
        }
        observer.unobserve(entry.target);
      }
    });
  }, { threshold: 0.12, rootMargin: '0px 0px -50px 0px' });

  revealEls.forEach(el => observer.observe(el));
}

// ── NAV SCROLL BEHAVIOUR ───────────────────────────────────
function initNav() {
  const nav = document.getElementById('nav');
  if (!nav) return;

  // Scrolled class
  window.addEventListener('scroll', () => {
    nav.classList.toggle('scrolled', window.scrollY > 20);
  }, { passive: true });

  // Active link highlighting
  const sections = document.querySelectorAll('section[id]');
  const navLinks = document.querySelectorAll('.nav__link[data-href]');

  function setActiveLink() {
    const scrollPos = window.scrollY + 120;
    sections.forEach(sec => {
      const top    = sec.offsetTop;
      const bottom = top + sec.offsetHeight;
      if (scrollPos >= top && scrollPos < bottom) {
        navLinks.forEach(link => {
          link.classList.toggle('active', link.dataset.href === `#${sec.id}`);
        });
      }
    });
  }

  window.addEventListener('scroll', setActiveLink, { passive: true });
  setActiveLink();

  // Hamburger
  const hamburger   = document.getElementById('hamburger');
  const mobileMenu  = document.getElementById('mobileMenu');

  if (hamburger && mobileMenu) {
    hamburger.addEventListener('click', () => {
      const open = hamburger.classList.toggle('open');
      mobileMenu.classList.toggle('open', open);
      hamburger.setAttribute('aria-expanded', open);
    });

    // Close mobile menu on link click
    mobileMenu.querySelectorAll('a').forEach(link => {
      link.addEventListener('click', () => {
        hamburger.classList.remove('open');
        mobileMenu.classList.remove('open');
        hamburger.setAttribute('aria-expanded', false);
      });
    });
  }
}

// ── COUNTER TRIGGER ON HERO IN VIEW ───────────────────────
function initHeroCounters() {
  const heroStats = document.querySelector('.hero__stats');
  if (!heroStats) return;

  const obs = new IntersectionObserver((entries) => {
    if (entries[0].isIntersecting) {
      animateCounters();
      obs.disconnect();
    }
  }, { threshold: 0.5 });

  obs.observe(heroStats);
}

// ── MAIN RENDER ────────────────────────────────────────────
function renderAll(content) {
  try {
    renderNav(content);
    renderHero(content);
    renderAbout(content);
    renderSkills(content);
    renderExperience(content);
    renderProjects(content);
    renderAI(content);
    renderOpenSource(content);
    renderAchievements(content);
    renderEducation(content);
    renderContact(content);
    renderFooter(content);

    // Init interactions after render
    requestAnimationFrame(() => {
      initNav();
      initScrollReveal();
      initHeroCounters();
      initTypingAnimation(content.personal.typingWords);
    });

  } catch (err) {
    console.error('[Portfolio] Render error:', err);
    document.body.insertAdjacentHTML('afterbegin', `
      <div style="background:#FEE2E2;color:#DC2626;padding:1rem;font-family:monospace;position:fixed;top:0;left:0;right:0;z-index:9999;font-size:.875rem;">
        ⚠️ Portfolio render error: ${err.message} — Check console for details.
      </div>
    `);
  }
}

// ── BOOT ───────────────────────────────────────────────────
document.addEventListener('DOMContentLoaded', () => {
  if (typeof PORTFOLIO_CONTENT === 'undefined') {
    console.error('[Portfolio] PORTFOLIO_CONTENT not found. Make sure content.js is loaded before app.js.');
    return;
  }
  renderAll(PORTFOLIO_CONTENT);
});
